/**
 * File Upload API for Settings
 * Author: generated by Amazon Q
 * Created: 2024-12-20
 */

import { NextRequest, NextResponse } from 'next/server';
import { put } from '@vercel/blob';

// Configure route for large file uploads
export const runtime = 'nodejs';
export const maxDuration = 60; // Maximum execution time in seconds
export const dynamic = 'force-dynamic';

export async function POST(request: NextRequest) {
  try {
    let formData;
    try {
      formData = await request.formData();
    } catch (parseError) {
      console.error('FormData parse error:', parseError);
      return NextResponse.json(
        { success: false, error: 'Failed to parse upload data. File may be too large or request was interrupted.' },
        { status: 400 }
      );
    }

    const file = formData.get('file') as File;
    const type = formData.get('type') as string;

    if (!file) {
      return NextResponse.json(
        { success: false, error: 'No file provided' },
        { status: 400 }
      );
    }

    if (!type || !['logo', 'logo-light', 'logo-dark', 'favicon', 'media'].includes(type)) {
      return NextResponse.json(
        { success: false, error: 'Invalid file type' },
        { status: 400 }
      );
    }

    // Validate file size (max 100MB for videos, 5MB for images)
    const maxSize = file.type.startsWith('video/') ? 100 * 1024 * 1024 : 5 * 1024 * 1024;
    if (file.size > maxSize) {
      const maxSizeText = file.type.startsWith('video/') ? '100MB' : '5MB';
      return NextResponse.json(
        { success: false, error: `File size too large (max ${maxSizeText})` },
        { status: 400 }
      );
    }

    // Validate file type
    const allowedTypes = {
      logo: ['image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/svg+xml', 'image/webp'],
      'logo-light': ['image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/svg+xml', 'image/webp'],
      'logo-dark': ['image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/svg+xml', 'image/webp'],
      favicon: ['image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/x-icon', 'image/vnd.microsoft.icon', 'image/webp'],
      media: [
        'image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/svg+xml', 'image/webp',
        'video/mp4', 'video/webm', 'video/ogg', 'video/quicktime', 'video/x-msvideo'
      ]
    };

    if (!allowedTypes[type as keyof typeof allowedTypes].includes(file.type)) {
      return NextResponse.json(
        { success: false, error: `Invalid file type for ${type}. Allowed: ${allowedTypes[type as keyof typeof allowedTypes].join(', ')}` },
        { status: 400 }
      );
    }

    // Generate unique filename
    const timestamp = Date.now();
    const extension = file.name.split('.').pop();
    const filename = `settings/${type}-${timestamp}.${extension}`;

    try {
      // Upload to Vercel Blob
      const blob = await put(filename, file, {
        access: 'public',
        addRandomSuffix: false,
      });

      // Return public URL
      const publicUrl = blob.url;

      return NextResponse.json({
        success: true,
        url: publicUrl,
        filename,
        size: file.size,
        type: file.type
      });
    } catch (uploadError) {
      console.error('Vercel Blob upload error:', uploadError);
      return NextResponse.json(
        { success: false, error: uploadError instanceof Error ? uploadError.message : 'Failed to upload to storage' },
        { status: 500 }
      );
    }

  } catch (error) {
    console.error('Upload error:', error);
    return NextResponse.json(
      { success: false, error: error instanceof Error ? error.message : 'Failed to upload file' },
      { status: 500 }
    );
  }
}